      /* (3520) bare_label_keyword ::= TEXT_P */ yytestcase(yyruleno==3520);
      /* (3521) bare_label_keyword ::= THEN */ yytestcase(yyruleno==3521);
      /* (3522) bare_label_keyword ::= TIES */ yytestcase(yyruleno==3522);
      /* (3523) bare_label_keyword ::= TIME */ yytestcase(yyruleno==3523);
      /* (3524) bare_label_keyword ::= TIMESTAMP */ yytestcase(yyruleno==3524);
      /* (3525) bare_label_keyword ::= TRAILING */ yytestcase(yyruleno==3525);
